// Parse incoming body (sent as text/plain from the browser)
const raw = $('Receive trip request').item.json.body;
let body;
try { body = typeof raw === 'string' ? JSON.parse(raw) : (raw || {}); }
catch(e) { body = {}; }

const SYSTEM = `You are an expert travel planner. Return ONLY a valid JSON object — no markdown, no extra text.

Return this exact structure:
{
  "id": "custom",
  "city": "<city>",
  "country": "<country>",
  "persona": "<persona>",
  "days": 3,
  "tagline": "<one evocative sentence>",
  "plan": [
    { "day": 1, "title": "<Day title>", "items": [
      { "time": "9:00 AM", "title": "<activity>", "cat": "<dining|cruise|adventure|relaxing|sightseeing>", "cost": 0, "tip": "<two specific sentences>", "kids": false }
    ]}
  ],
  "omitted": [
    { "time": "Evening", "title": "<backup>", "cat": "relaxing", "cost": 20, "tip": "<tip>" }
  ]
}
Rules: 3-5 items/day, vary categories, exactly 3 omitted items, real place names.
Persona: Budget=cheap, Mid-range=comfortable, Luxurious=premium, Adventure=active.`;

const dest = body.destination || 'Paris';
const days = body.days || 3;
const persona = body.persona || 'Mid-range';
const adults = (body.adults_m||0)+(body.adults_f||0)||2;
const kids = body.kids||0;
const dates = `${body.startDate||'flexible'} to ${body.endDate||'flexible'}`;
const must = body.mustHave||'none';

const userMsg = body._ping
  ? `Say: {"pong":true,"status":"ok","city":"Test","country":"OK","persona":"Mid-range","days":1,"tagline":"Connection test","plan":[{"day":1,"title":"Test","items":[{"time":"9:00 AM","title":"Test activity","cat":"sightseeing","cost":0,"tip":"This is a test.","kids":false}]}],"omitted":[{"time":"Evening","title":"Test backup","cat":"relaxing","cost":0,"tip":"Test."},{"time":"Morning","title":"Test 2","cat":"dining","cost":0,"tip":"Test."},{"time":"Afternoon","title":"Test 3","cat":"adventure","cost":0,"tip":"Test."}]}`
  : `Plan a ${days}-day ${persona} trip to ${dest}.\nGroup: ${adults} adult(s), ${kids} kid(s). Dates: ${dates}. Must-haves: ${must}.`;

return [{ json: {
  geminiPayload: JSON.stringify({
    contents: [{ role: 'user', parts: [{ text: userMsg }] }],
    systemInstruction: { parts: [{ text: SYSTEM }] },
    generationConfig: {
      responseMimeType: 'application/json',
      maxOutputTokens: 4096,
      temperature: 0.7
    }
  })
}}];

const r = $input.item.json;

if (!r.candidates || !r.candidates.length) {
  return [{ json: { error: true, message: 'Gemini returned no candidates. Check your API key. Response: ' + JSON.stringify(r).slice(0,300) } }];
}

const text = r.candidates[0]?.content?.parts?.[0]?.text;
if (!text) return [{ json: { error: true, message: 'Gemini returned empty text.' } }];

let trip;
try {
  trip = JSON.parse(text.replace(/^```json\s*/i,'').replace(/```\s*$/i,'').trim());
} catch(e) {
  return [{ json: { error: true, message: 'Gemini output not valid JSON: ' + text.slice(0,200) } }];
}

if (!trip.plan || !Array.isArray(trip.plan)) {
  return [{ json: { error: true, message: 'Missing plan array: ' + JSON.stringify(trip).slice(0,200) } }];
}
if (!Array.isArray(trip.omitted)) trip.omitted = [];

const validCats = new Set(['dining','cruise','adventure','relaxing','sightseeing']);
for (const day of trip.plan) {
  for (const item of (day.items||[])) {
    if (!validCats.has(item.cat)) item.cat = 'sightseeing';
    if (typeof item.cost !== 'number') item.cost = 0;
    if (typeof item.kids !== 'boolean') item.kids = false;
    if (!item.tip) item.tip = 'A wonderful experience.';
  }
}
if (trip.omitted.length < 3) {
  while (trip.omitted.length < 3) trip.omitted.push({ time: 'Evening', title: 'Local evening activity', cat: 'relaxing', cost: 15, tip: 'Ask locals for recommendations.' });
}
trip.id = trip.id || 'custom';
return [{ json: trip }];
